"""
MKT Christ Commentary — Proverbs chapters 4–6
Run: python3 scripts/zc-christ-proverbs-4-6.py

Ch4: Father-son wisdom transmission — Christ as the obedient Son who perfectly
     receives the Father's instruction (John 5:19-20); wisdom personification
     begins (vv6-9) pointing toward ch8's Wisdom = Christ (1 Cor 1:30);
     the two paths (vv18-19) → John 8:12; the heart as life-source (v23) → John 4:14
Ch5: Warning against the strange woman — positive counterpart (wife of your youth,
     vv15-18) → Eph 5:25-27 (Christ's love for the church-bride); v5 (feet go to
     death) → Christ descending to death (Eph 4:9); v1 surety intro → Heb 7:22
Ch6: Surety (vv1-5) → Christ as guarantor of the new covenant (Heb 7:22);
     ant/diligence → Christ's constant labor (John 5:17); lamp/light (v23) → John 8:12;
     seven abominations (vv16-19) → Christ as the positive counter-profile (Beatitudes);
     adultery-section → Christ the faithful husband (Eph 5:25-32)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "4": {
    "1": "<p>The father&rsquo;s call &ldquo;Hear, O sons, a father&rsquo;s instruction&rdquo; frames the whole of Proverbs 4 as the transmission of the father&rsquo;s <em>bînāh</em> (understanding) to his sons. Christ is the eternal Son who uniquely receives and embodies the Father&rsquo;s instruction without remainder: &ldquo;the Son can do nothing of his own accord, but only what he sees the Father doing&rdquo; (John 5:19). Every human father-son wisdom transmission in Proverbs is a creaturely echo of the eternal Father-Son relationship in which all wisdom originates.</p>",
    "2": "<p>&ldquo;I give you good instruction (<em>leqaḥ ṭôb</em>); do not forsake my teaching.&rdquo; The <em>leqaḥ</em> (teaching received) that the father passes on is ultimately grounded in what God teaches. Isaiah 50:4-5 presents the Servant as one whose ear YHWH has opened morning by morning to receive instruction; Christ is the supreme Servant-son whose teaching is the Father&rsquo;s own (John 7:16: &ldquo;my teaching is not mine, but his who sent me&rdquo;). The father&rsquo;s <em>leqaḥ ṭôb</em> anticipates the Son&rsquo;s reception of perfect divine instruction.</p>",
    "3": "<p>The father&rsquo;s recollection of his own boyhood under his father&rsquo;s tender care establishes the intergenerational chain: grandfather to father to son. The eternal generation of the Son is the divine ground of all fatherly wisdom-transmission: &ldquo;I and the Father are one&rdquo; (John 10:30); the eternal Son has been with the Father &ldquo;before the foundation of the world&rdquo; (John 17:24). Every human wisdom tradition traces back to the source of all wisdom — the eternal Father-Son relationship.</p>",
    "4": "<p>&ldquo;Let your heart hold fast my words; keep my commandments, and live.&rdquo; The father commands what Christ alone perfectly performed: John 15:10 — &ldquo;I have kept my Father&rsquo;s commandments and abide in his love.&rdquo; The <em>ḥăyēh</em> (live!) here anticipates John 5:21 — as the Father raises the dead and gives life, so the Son gives life to whom he will. Christ kept the Father&rsquo;s commands with perfect heart-loyalty and in doing so acquired life on behalf of those who cannot keep them.</p>",
    "5": "<p>&ldquo;Get wisdom, get understanding; do not forget, and do not turn away from the words of my mouth.&rdquo; Paul identifies Christ directly as &ldquo;wisdom from God&rdquo; (1 Cor 1:30) and &ldquo;in whom are hidden all the treasures of wisdom and knowledge&rdquo; (Col 2:3). The imperative to &ldquo;get wisdom&rdquo; is ultimately an imperative that finds its fulfillment in coming to Christ: the one who comes to him receives the wisdom the Father offers (Matt 11:28-29: &ldquo;learn from me&rdquo;).</p>",
    "6": "<p>&ldquo;Do not forsake her, and she will keep you; love her, and she will guard you.&rdquo; Wisdom is personified as one who keeps and guards her lover — the first emergence of the Wisdom figure who will be fully developed in ch8. Christ as the embodied Wisdom keeps those who are his: &ldquo;I give them eternal life, and they will never perish, and no one will snatch them out of my hand&rdquo; (John 10:28). The faithful keeping that Wisdom promises is the security that Christ provides.</p>",
    "7": "<p>&ldquo;The beginning of wisdom is this: get wisdom, and whatever you get, get insight.&rdquo; The LXX renders &ldquo;the beginning&rdquo; (<em>rēʾšît</em>) with <em>archē</em> — the same word used in John 1:1 (&ldquo;In the beginning was the Word&rdquo;) and Col 1:18 (&ldquo;he is the beginning, the firstborn from the dead&rdquo;). The first principle of all wisdom is to acquire the Wisdom who is the <em>archē</em> of creation — the one in whom and through whom all things were made (Col 1:16).</p>",
    "8": "<p>&ldquo;Prize her highly, and she will exalt you; she will honor you if you embrace her.&rdquo; The mutual exaltation pattern — wisdom exalts those who prize her — finds its ultimate expression in the pattern of Christ&rsquo;s humiliation and exaltation: Phil 2:9, &ldquo;God has highly exalted him and bestowed on him the name that is above every name.&rdquo; Those who embrace Christ, the true Wisdom, participate in his exaltation: &ldquo;I confer on you a kingdom&rdquo; (Luke 22:29); &ldquo;if we endure, we will also reign with him&rdquo; (2 Tim 2:12).</p>",
    "9": "<p>&ldquo;She will place on your head a graceful garland; she will bestow on you a beautiful crown.&rdquo; The crown (ʿăṭeret) bestowed by Wisdom points to the eschatological crown promised to the faithful. Revelation 2:10: &ldquo;be faithful unto death, and I will give you the crown of life.&rdquo; James 1:12: &ldquo;the crown of life, which God has promised to those who love him.&rdquo; Christ himself wore the crown of thorns (Matt 27:29) on the way to receiving &ldquo;a crown of glory that will never fade away&rdquo; (1 Pet 5:4), securing the honor-crown for all who embrace wisdom.</p>",
    "10": "<p>&ldquo;Hear, my son, and accept my words, that the years of your life may be many.&rdquo; The promise of long life for wisdom-reception is fulfilled in its deepest sense by Christ, who by his death and resurrection made life-in-fullness available: &ldquo;I am the resurrection and the life. Whoever believes in me, though he die, yet shall he live&rdquo; (John 11:25). The &ldquo;many years&rdquo; of temporal wisdom expands into eternal life in the one who is both the giver and the content of wisdom.</p>",
    "11": "<p>&ldquo;I have taught you the way of wisdom; I have led you in the paths of uprightness.&rdquo; The father&rsquo;s instruction in the way of wisdom is the temporal pattern of what the Spirit of Truth performs in Christ&rsquo;s people: &ldquo;when the Spirit of truth comes, he will guide you into all the truth&rdquo; (John 16:13). Christ taught his disciples the way of wisdom by example and word, and sends his Spirit to lead those who follow him into the paths of uprightness permanently.</p>",
    "12": "<p>&ldquo;When you walk, your step will not be hampered, and if you run, you will not stumble.&rdquo; The unhamperedpath of wisdom is fulfilled in Christ who navigated the path of perfect obedience without stumbling: Heb 4:15 — &ldquo;one who in every respect has been tempted as we are, yet without sin.&rdquo; He is the path-finder who went before, and through his Spirit enables those who follow him to run without stumbling (Jude 24: &ldquo;him who is able to keep you from stumbling&rdquo;).</p>",
    "13": "<p>&ldquo;Keep hold of instruction; do not let go; guard her, for she is your life.&rdquo; Instruction (<em>mûsār</em>) is identified with life itself — the one who holds it, holds life. Christ is the life (John 14:6: &ldquo;I am the way, and the truth, and the life&rdquo;) and the giver of life: &ldquo;I came that they may have life and have it abundantly&rdquo; (John 10:10). The grip on instruction that Proverbs commands corresponds to the clinging faith that receives what Christ alone can give: himself as life.</p>",
    "14": "<p>&ldquo;Do not enter the path of the wicked, and do not walk in the way of evil men.&rdquo; The two-path structure — wisdom&rsquo;s way versus the wicked&rsquo;s path — finds its NT counterpart in Jesus&rsquo; two-road teaching: &ldquo;the gate is wide and the way is easy that leads to destruction... the gate is narrow and the way is hard that leads to life&rdquo; (Matt 7:13-14). Christ is the narrow gate and the hard way; he also is the one who walked it without wavering.</p>",
    "15": "<p>&ldquo;Avoid it; do not go on it; turn away from it and pass on.&rdquo; The radical avoidance of the wicked path — turn away and pass on — reflects the single-minded focus on wisdom&rsquo;s way. Hebrews 12:1-2 applies the same concentrated focus to the race of faith: &ldquo;let us run with endurance the race that is set before us, looking to Jesus, the founder and perfecter of our faith.&rdquo; Christ himself was the one who &ldquo;turned away&rdquo; from every temptation presented in the wilderness (Luke 4:1-13), modeling the radical refusal of the wicked path.</p>",
    "16": "<p>&ldquo;For they cannot sleep unless they have done evil; they are robbed of sleep unless they have made someone stumble.&rdquo; The wicked person&rsquo;s insatiable appetite for harm is the darkest expression of human depravity — active, purposeful, restless evil. Christ&rsquo;s adversary, &ldquo;a roaring lion, seeking someone to devour&rdquo; (1 Pet 5:8), operates in precisely this pattern of restless, purposeful destruction. Against this adversary, Christ declares: &ldquo;I will build my church, and the gates of hell shall not prevail against it&rdquo; (Matt 16:18).</p>",
    "17": "<p>&ldquo;For they eat the bread of wickedness and drink the wine of violence.&rdquo; The wicked feast on violence as their daily sustenance — the inversion of the covenant meal. At the Last Supper, Jesus offered bread and wine as the meal of the new covenant (Luke 22:19-20): his body broken and blood shed for those who had feasted on wickedness and violence, transforming the table of death into the table of life. The violent men&rsquo;s wine of violence is displaced by the cup of the new covenant in his blood.</p>",
    "18": "<p>&ldquo;But the path of the righteous is like the light of dawn, which shines brighter and brighter until full day.&rdquo; This verse is the OT background for one of Christ&rsquo;s most direct self-identifications: &ldquo;I am the light of the world. Whoever follows me will not walk in darkness, but will have the light of life&rdquo; (John 8:12). The &ldquo;full day&rdquo; of the righteous man&rsquo;s path corresponds to Rev 22:5: &ldquo;night will be no more. They will need no light of lamp or sun, for the Lord God will be their light.&rdquo; Christ is the eschatological full day toward which wisdom&rsquo;s dawn points.</p>",
    "19": "<p>&ldquo;The way of the wicked is like deep darkness; they do not know over what they stumble.&rdquo; The darkness metaphor for evil and its consequences appears throughout John&rsquo;s Gospel: &ldquo;people loved the darkness rather than the light because their works were evil&rdquo; (John 3:19). The wicked &ldquo;do not know over what they stumble&rdquo; — a description of those who crucified Christ: &ldquo;Father, forgive them, for they know not what they do&rdquo; (Luke 23:34); Paul echoes this: &ldquo;if they had understood it, they would not have crucified the Lord of glory&rdquo; (1 Cor 2:8).</p>",
    "20": "<p>&ldquo;My son, be attentive to my words; incline your ear to my sayings.&rdquo; The reiterated call to attentiveness — the Shema posture of receiving instruction — is the creaturely response that the Father calls for from his people. Christ is the one who performs perfect attentiveness: &ldquo;the Father who sent me has himself given me a commandment — what to say and what to speak&rdquo; (John 12:49). The Son&rsquo;s perfect attentiveness to the Father is the model and the source of the disciple&rsquo;s learning to hear.</p>",
    "21": "<p>&ldquo;Let them not escape from your sight; keep them within your heart.&rdquo; The command to hold wisdom within the heart reflects the new covenant promise: &ldquo;I will put my law within them, and I will write it on their hearts&rdquo; (Jer 31:33). Christ is the mediator of the new covenant (Heb 9:15) through whose Spirit the law is inscribed within rather than external — the wisdom that previously had to be held by constant discipline becomes a living reality in the Spirit-formed heart.</p>",
    "22": "<p>&ldquo;For they are life to those who find them, and healing to all their flesh.&rdquo; Wisdom&rsquo;s words as life and healing for the whole person point to Christ as the physician who heals both soul and body: &ldquo;which is easier, to say... &lsquo;Your sins are forgiven,&rsquo; or to say, &lsquo;Rise and walk&rsquo;?&rdquo; (Matt 9:5). The completeness of healing — spirit, soul, and body — is achieved in the resurrection of Christ, whose resurrection body is the prototype of the fullness of healing that awaits those who are his (1 Cor 15:42-44).</p>",
    "23": "<p>&ldquo;Keep your heart with all vigilance, for from it flow the springs of life.&rdquo; The heart as the source of life&rsquo;s streams points toward John 4:14 — Christ promises the Samaritan woman &ldquo;a spring of water welling up to eternal life&rdquo; — and John 7:38: &ldquo;whoever believes in me... out of his heart will flow rivers of living water.&rdquo; The heart that is guarded by wisdom becomes, through Christ&rsquo;s indwelling Spirit, a spring that flows outward rather than merely inward.</p>",
    "24": "<p>&ldquo;Put away from you crooked speech, and put devious talk far from you.&rdquo; The purified speech of the wisdom-formed person reflects the mouth of Christ, in whom &ldquo;no guile was found&rdquo; (1 Pet 2:22; Isa 53:9). Christ is the Servant who set his face and did not speak deviousness; he is also the one who declares &ldquo;the truth will set you free&rdquo; (John 8:32) and identifies himself as &ldquo;the truth&rdquo; (John 14:6). The positive ideal of crooked-speech-avoidance reaches its absolute in the one who is truth itself.</p>",
    "25": "<p>&ldquo;Let your eyes look directly forward, and your gaze be straight before you.&rdquo; The undivided, forward focus of wisdom is fulfilled in Christ&rsquo;s own resolution: &ldquo;he set his face to go to Jerusalem&rdquo; (Luke 9:51). Hebrews 12:2 describes Christ as the one who endured the cross &ldquo;for the joy that was set before him&rdquo; — forward-focused, undiverted, completing the path with his eyes fixed on the Father&rsquo;s purpose. The disciple is called to the same forward gaze: &ldquo;no one who puts his hand to the plow and looks back is fit for the kingdom&rdquo; (Luke 9:62).</p>",
    "26": "<p>&ldquo;Ponder the path of your feet; then all your ways will be sure.&rdquo; The careful self-examination of one&rsquo;s path is the wisdom virtue of moral attention — the regular examination of whether one&rsquo;s trajectory is wisdom&rsquo;s way or the wicked&rsquo;s path. Christ as the Good Shepherd examined and guarded the path of each sheep: &ldquo;he calls his own sheep by name&rdquo; (John 10:3). The Spirit of Truth in believers performs the pondering function from within: &ldquo;he will convict the world concerning sin and righteousness and judgment&rdquo; (John 16:8).</p>",
    "27": "<p>&ldquo;Do not swerve to the right or to the left; turn your foot away from evil.&rdquo; The command to stay on wisdom&rsquo;s straight path without deviation echoes Deuteronomy&rsquo;s covenant faithfulness language (Deut 5:32; Josh 1:7). Christ is the only human being who perfectly fulfilled this command: Heb 7:26 describes him as &ldquo;holy, innocent, unstained, separated from sinners.&rdquo; His sinless path is both the model and the foundation: his undeviating obedience provides the righteousness that his followers lack (Rom 5:19: &ldquo;by the one man&rsquo;s obedience the many will be made righteous&rdquo;).</p>"
  },
  "5": {
    "1": "<p>&ldquo;My son, be attentive to my wisdom; incline your ear to my understanding.&rdquo; The chapter&rsquo;s opening call to wisdom-hearing introduces the warning against the strange woman — the wisdom-versus-folly contrast in sexual form. Christ addressed the sexual ethics of the heart directly: &ldquo;I say to you that everyone who looks at a woman with lustful intent has already committed adultery with her in his heart&rdquo; (Matt 5:28), going deeper than Proverbs&rsquo; behavioral warning to the source of the behavior. Christ&rsquo;s wisdom penetrates where the father&rsquo;s instruction cannot follow — into the heart.</p>",
    "2": "<p>&ldquo;That you may keep discretion, and your lips may guard knowledge.&rdquo; The kept discretion and guarded knowledge of wisdom&rsquo;s way are the opposite of the dripping-honey lips of the strange woman (v3). Christ is the one who speaks truth, life, and discretion: &ldquo;the words that I have spoken to you are spirit and life&rdquo; (John 6:63). His lips do not drip seductive flattery but speak the hard truth that leads to life; his words guard those who receive them.</p>",
    "3": "<p>&ldquo;For the lips of a forbidden woman drip honey, and her speech is smoother than oil.&rdquo; The sweet-seductive speech of the strange woman is the counterfeit of wisdom&rsquo;s true speech. Peter&rsquo;s description of false teachers mirrors Proverbs&rsquo; warning: &ldquo;with bold faces they will exploit you&rdquo; (2 Pet 2:3); Jude 12: &ldquo;hidden reefs at your love feasts, feasting with you without fear.&rdquo; Against all false and seductive speech, Christ sets his own: &ldquo;no one ever spoke like this man&rdquo; (John 7:46) — distinctive, authoritative, and life-giving.</p>",
    "4": "<p>&ldquo;But in the end she is bitter as wormwood, sharp as a two-edged sword.&rdquo; The reversal from sweetness to bitterness, from smoothness to cutting sharpness, is the trajectory of all false paths. Hebrews 4:12 applies the two-edged sword image to the word of God itself — &ldquo;sharper than any two-edged sword, piercing to the division of soul and of spirit&rdquo; — but there the sharpness serves discernment and life. The strange woman&rsquo;s sword-sharpness wounds to death; Christ&rsquo;s sword-word cuts for healing and truth.</p>",
    "5": "<p>&ldquo;Her feet go down to death; her steps follow the path to Sheol.&rdquo; The descent to Sheol that follows the strange woman&rsquo;s path becomes, in the NT, the descent that Christ undertook to rescue those already there. Ephesians 4:9-10 reads the Psalms&rsquo; language of Christ&rsquo;s descent: &ldquo;he also descended into the lower regions, the earth.&rdquo; Acts 2:27 cites Ps 16:10: &ldquo;you will not abandon my soul to Hades.&rdquo; The feet that go down to Sheol in Proverbs describe the path of sin; Christ descended to that same Sheol to lead captives out (Eph 4:8).</p>",
    "6": "<p>&ldquo;She does not ponder the path of life; her ways wander, and she does not know it.&rdquo; The strange woman&rsquo;s unconscious wandering — not pondering the path of life, not knowing she wanders — is the condition of those who need the shepherd. Luke 15:4: &ldquo;what man of you, having a hundred sheep, if he has lost one of them, does not leave the ninety-nine in the open country, and go after the one that is lost, until he finds it?&rdquo; Christ comes to seek those who wander without knowing it — the lost sheep of a house that does not know the way of life.</p>",
    "7": "<p>&ldquo;And now, O sons, listen to me, and do not depart from the words of my mouth.&rdquo; The urgent renewal of the call to hear — &ldquo;now&rdquo; (<em>weʿattāh</em>) — reflects the earnestness of wisdom at every point. Christ&rsquo;s own urgent calls to hear carry this same register: &ldquo;the hour is coming and is now here&rdquo; (John 5:25); &ldquo;unless you repent, you will all likewise perish&rdquo; (Luke 13:3). The wisdom tradition&rsquo;s urgency is the earthly form of the eschatological urgency that Christ brings into the present moment.</p>",
    "8": "<p>&ldquo;Keep your way far from her, and do not go near the door of her house.&rdquo; The spatial language of danger-avoidance — stay far, do not come near — frames temptation as a domain to be avoided rather than a battle to be fought at close quarters. Hebrews 12:2 points to the wisdom of fixing one&rsquo;s gaze on Christ rather than on the temptation: &ldquo;looking to Jesus, the founder and perfecter of our faith.&rdquo; Distance from the temptation is achieved by proximity to Christ — &ldquo;flee youthful passions and pursue righteousness, faith, love, and peace&rdquo; (2 Tim 2:22).</p>",
    "9": "<p>&ldquo;Lest you give your honor to others and your years to the merciless.&rdquo; The strange woman steals the young man&rsquo;s honor and years — his strength, dignity, and life. Christ restores what sin strips away: &ldquo;I came to give abundant life&rdquo; (John 10:10); the prodigal son who spent his inheritance in a foreign country receives back robe, ring, and feast from the father (Luke 15:22-24). The honor stripped by folly is restored by the grace of the Father who runs to meet the returning son.</p>",
    "10": "<p>&ldquo;Lest strangers take their fill of your strength, and your labors go to the house of a foreigner.&rdquo; The exploitation of strength and labor by strangers/foreigners echoes the Deuteronomic curse: &ldquo;a nation that you do not know shall eat up the fruit of your ground and of all your labors&rdquo; (Deut 28:33). Christ reverses this curse: Gal 3:13 — &ldquo;Christ redeemed us from the curse of the law.&rdquo; The strength and labor that belong to the one who is his are not consumed by a pitiless stranger but become the material of the new creation that the Spirit cultivates within.</p>",
    "11": "<p>&ldquo;And at the end of your life you groan, when your flesh and body are consumed.&rdquo; The end-of-life groaning of the one who spent his years in folly is the experiential endpoint of the path that began at the strange woman&rsquo;s door. Paul uses similar groaning language for the unredeemed condition of the created order and the human body: &ldquo;we ourselves groan inwardly as we wait eagerly for adoption as sons, the redemption of our bodies&rdquo; (Rom 8:23). The groan of regret becomes, through Christ, the groan of hopeful anticipation — the same word transformed by the resurrection promise.</p>",
    "12": "<p>&ldquo;And you say, &lsquo;How I hated instruction!&rsquo;&rdquo; The deathbed realization that instruction was despised captures the tragic self-knowledge that comes too late. Christ&rsquo;s parable of the rich man and Lazarus (Luke 16:19-31) presents exactly this end-of-life insight arriving too late for remedy. The compassionate invitation of the wisdom teacher — &ldquo;come to me and learn&rdquo; (Matt 11:28-29) — is the open door before which the one who despised instruction stands. The &ldquo;how I hated instruction&rdquo; lament is the background against which Christ&rsquo;s gracious invitation stands in relief.</p>",
    "13": "<p>&ldquo;I did not listen to the voice of my teachers or incline my ear to my instructors.&rdquo; The failure to hear the teachers is the individual instance of Israel&rsquo;s structural failure to hear the prophets: &ldquo;I sent to you all my servants the prophets, sending them persistently, but you did not listen&rdquo; (Jer 29:19). Christ stands at the end of that prophetic line as the Son: &ldquo;he had still one other, a beloved son. Finally he sent him to them, saying, &lsquo;They will respect my son&rsquo;&rdquo; (Mark 12:6). The failure to hear the teachers culminates in the crucifixion of the Son.</p>",
    "14": "<p>&ldquo;I am at the brink of utter ruin in the assembled congregation.&rdquo; The near-ruin of the man overtaken by folly in the midst of the covenant community — the public, communal dimension of shame — corresponds to the shame Christ bore publicly: &ldquo;enduring the cross, despising the shame&rdquo; (Heb 12:2). Christ bore the covenant community&rsquo;s judgment on the covenant-breaker publicly, outside the gate (Heb 13:12), so that those at the brink of ruin might be brought back within the congregation through his substitution.</p>",
    "15": "<p>&ldquo;Drink water from your own cistern, flowing water from your own well.&rdquo; The positive counterpart to the strange woman&rsquo;s seduction is the covenant marriage relationship — exclusive, refreshing, life-giving. Ephesians 5:25-27 applies the marriage relationship directly to Christ and the church: Christ loved the church and gave himself up for her. The cistern-and-well imagery of faithful marriage becomes, in the NT, the picture of Christ&rsquo;s own exclusive covenant love for his bride-community (Rev 21:2: the new Jerusalem as a bride adorned for her husband).</p>",
    "16": "<p>&ldquo;Should your springs be scattered abroad, streams of water in the streets?&rdquo; The rhetorical question — implying the answer &ldquo;no&rdquo; — concerns the exclusive channeling of marital love to the covenant wife. Christ&rsquo;s love for the church is not scattered but precisely directed: he gave himself &ldquo;for her&rdquo; (Eph 5:25). Yet paradoxically, the living water Christ gives flows outward from his people to all: &ldquo;out of his heart will flow rivers of living water&rdquo; (John 7:38) — the exclusive covenant fidelity produces an abundant outward overflow rather than a contained private resource.</p>",
    "17": "<p>&ldquo;Let them be for yourself alone, and not for strangers with you.&rdquo; The exclusivity of the marriage covenant — the wife and her love belong to one husband — is the temporal image of Christ&rsquo;s exclusive covenant with his people. 2 Cor 11:2 uses the betrothal image: &ldquo;I betrothed you to one husband, to present you as a pure virgin to Christ.&rdquo; The &ldquo;strangers&rdquo; who threaten the exclusivity of the covenant marriage correspond to the false gospels and seductions that threaten to draw the church away from her exclusive devotion to Christ.</p>",
    "18": "<p>&ldquo;Let your fountain be blessed, and rejoice in the wife of your youth.&rdquo; The blessing of the marriage fountain and the rejoicing in the covenant wife are positive commands that correspond to Christ&rsquo;s own delight in his people. Zeph 3:17: &ldquo;he will rejoice over you with gladness; he will quiet you by his love; he will exult over you with loud singing.&rdquo; The husband&rsquo;s rejoicing in the wife of his youth is the temporal image of the divine rejoicing over the covenant community — and ultimately over the bride purified by Christ for the Father&rsquo;s pleasure.</p>",
    "19": "<p>&ldquo;A lovely deer, a graceful doe — let her breasts fill you at all times with delight; be intoxicated always in her love.&rdquo; The extravagant language of delight in covenant marriage — intoxicated always with love — matches the language of Song of Solomon and points toward the NT&rsquo;s marriage metaphor for Christ and the church. Revelation 19:7-9: &ldquo;the marriage of the Lamb has come, and his Bride has made herself ready... Blessed are those who are invited to the marriage supper of the Lamb.&rdquo; The exclusive delight of the faithful husband anticipates the eternal feast of mutual joy between Christ and his bride.</p>",
    "20": "<p>&ldquo;Why should you be intoxicated, my son, with a forbidden woman and embrace the bosom of an adulteress?&rdquo; The rhetorical &ldquo;why?&rdquo; addresses the absurdity of choosing folly when wisdom&rsquo;s delight is available — the same question that underlies the NT&rsquo;s &ldquo;how can we who died to sin still live in it?&rdquo; (Rom 6:2). The availability of Christ — &ldquo;for freedom Christ has set us free&rdquo; (Gal 5:1) — makes the return to folly not merely foolish but inexplicable in light of what has been given.</p>",
    "21": "<p>&ldquo;For a man&rsquo;s ways are before the eyes of YHWH, and he ponders all his paths.&rdquo; Divine omniscience of all human paths — YHWH sees and weighs each step — establishes the theological ground for moral accountability. Hebrews 4:13: &ldquo;no creature is hidden from his sight, but all are naked and exposed to the eyes of him to whom we must give account.&rdquo; Christ is identified as the one &ldquo;to whom we must give account&rdquo; — the judge whose seeing surpasses all concealment and before whom every path stands naked.</p>",
    "22": "<p>&ldquo;The iniquities of the wicked ensnare him, and he is held fast in the cords of his sin.&rdquo; Sin as self-binding cords — the sinner trapped by his own transgressions — describes the condition that Christ comes to release: &ldquo;if the Son sets you free, you will be free indeed&rdquo; (John 8:36). Isaiah 61:1 — &ldquo;to proclaim liberty to the captives&rdquo; — is the programmatic statement that Jesus applies to himself at Nazareth (Luke 4:18-19). The cords of sin that bind the wicked are what the cross severs for those united to Christ by faith.</p>",
    "23": "<p>&ldquo;He dies for lack of discipline, and because of his great folly he is led astray.&rdquo; The death of the undisciplined fool — led astray by his own folly — is the condition that makes the incarnation necessary. Christ came &ldquo;to seek and to save the lost&rdquo; (Luke 19:10); the sheep &ldquo;led astray&rdquo; by folly is precisely the one for whom the shepherd searches (Matt 18:12). The death-for-lack-of-discipline is answered by the one who, through suffering, learned obedience (Heb 5:8) and can now be &ldquo;the source of eternal salvation to all who obey him&rdquo; (Heb 5:9).</p>"
  },
  "6": {
    "1": "<p>&ldquo;My son, if you have put up security for your neighbor, have given your pledge for a stranger...&rdquo; The surety/pledge scenario introduces a critical typological dimension. Hebrews 7:22 identifies Christ as &ldquo;the guarantor (<em>engyos</em>) of a better covenant&rdquo; — the surety who put himself up as pledge for those who could not pay their own debt. The father&rsquo;s warning against reckless suretyship is the negative backdrop against which Christ&rsquo;s deliberate and wise assumption of the ultimate surety stands as the supreme act of loving wisdom.</p>",
    "2": "<p>&ldquo;...if you are snared in the words of your mouth, caught in the words of your mouth&rdquo; — being trapped by one&rsquo;s own pledge. Christ was not trapped by hasty words but by a deliberate, eternal covenant commitment: &ldquo;I have come to do your will, O God&rdquo; (Heb 10:9; Ps 40:7-8). His surety was not reckless but wholly intentional — he was &ldquo;the Lamb slain from the foundation of the world&rdquo; (Rev 13:8), whose pledge-giving was the eternal counsel of the Father, Son, and Spirit for redemption.</p>",
    "3": "<p>&ldquo;Then do this, my son, and save yourself, for you have come into the hand of your neighbor: go, hasten, and plead urgently with your neighbor.&rdquo; The urgent action to escape the surety trap — haste, humility, pleading — reflects the seriousness of being bound. Christ &ldquo;humbled himself by becoming obedient to the point of death&rdquo; (Phil 2:8), but his humiliation was not an escape from his surety obligation — it was the performance of it. He did not plea his way out but went all the way in, completing the pledge he had made on our behalf.</p>",
    "4": "<p>&ldquo;Give your eyes no sleep and your eyelids no slumber.&rdquo; The urgent sleeplessness required to escape the surety-trap evokes Christ&rsquo;s own Gethsemane watchfulness. He &ldquo;offered up prayers and supplications, with loud cries and tears, to him who was able to save him from death&rdquo; (Heb 5:7), remaining awake while the disciples slept (Matt 26:40-41: &ldquo;could you not watch with me one hour?&rdquo;). The sleepless urgency of the one who must deal with a binding obligation is fulfilled in Christ&rsquo;s awake, agonized faithfulness to his surety covenant.</p>",
    "5": "<p>&ldquo;Save yourself like a gazelle from the hand of the hunter, like a bird from the hand of the fowler.&rdquo; The animal escape-from-the-hunter imagery is used elsewhere to describe God&rsquo;s rescue of the soul (Ps 124:7: &ldquo;we have escaped like a bird from the snare of the fowlers&rdquo;). Christ&rsquo;s resurrection is the ultimate escape — not a flight from the hunter but a victory over death itself: &ldquo;he who has the power of death, that is, the devil&rdquo; (Heb 2:14) is destroyed, so that all those Christ represents are set free.</p>",
    "6": "<p>&ldquo;Go to the ant, O sluggard; consider her ways, and be wise.&rdquo; The ant&rsquo;s diligent, self-governed labor without external compulsion is the wisdom ideal of consistent productive work. Christ applied himself with complete diligence to the Father&rsquo;s work: &ldquo;My Father is working until now, and I am working&rdquo; (John 5:17); &ldquo;we must work the works of him who sent me while it is day; night is coming, when no one can work&rdquo; (John 9:4). Christ&rsquo;s constant work — healing, teaching, going about doing good (Acts 10:38) — is the perfect fulfillment of the ant&rsquo;s diligent wisdom.</p>",
    "7": "<p>&ldquo;Without having any chief, officer, or ruler, she prepares her bread in summer and gathers her food in harvest.&rdquo; The ant&rsquo;s self-governance without external authority points to the Spirit-formed self-discipline that Christ embodies and imparts. Paul&rsquo;s list of the Spirit&rsquo;s fruit (Gal 5:22-23) ends with <em>enkrateia</em> (self-control), the inward regulatory power that replaces the need for external enforcement. Christ sends the Spirit precisely to create this internal governance in his people, transforming the commanded diligence of Proverbs into a Spirit-produced reality.</p>",
    "8": "<p>&ldquo;She prepares her bread in summer and gathers her food in harvest.&rdquo; The seasonal wisdom of the ant — preparation in advance of need — reflects the providential foresight that Christ teaches: &ldquo;do not be anxious about tomorrow&rdquo; (Matt 6:34) is not a prohibition of planning but a reorientation of trust. Christ himself demonstrated providential foresight in feeding the five thousand (John 6:5-6: &ldquo;he himself knew what he would do&rdquo;), acting in advance of need with perfect provision.</p>",
    "9": "<p>&ldquo;How long will you lie there, O sluggard? When will you arise from your sleep?&rdquo; The prophetic question to the sluggard — when will you arise? — takes on eschatological weight in the NT&rsquo;s resurrection and wakefulness language: &ldquo;Awake, O sleeper, and arise from the dead, and Christ will shine on you&rdquo; (Eph 5:14). Christ&rsquo;s call to the spiritually dead is the ultimate answer to the question the sluggard cannot answer for himself — the arising comes not from the sleeper&rsquo;s own effort but from the voice that wakes the dead.</p>",
    "10": "<p>&ldquo;A little sleep, a little slumber, a little folding of the hands to rest, and poverty will come upon you like a robber.&rdquo; The poverty that comes like a robber on the unguarded sleeper contrasts with Christ&rsquo;s warning about the thief: &ldquo;the Son of Man is coming at an hour you do not expect&rdquo; (Matt 24:44). The sleeper&rsquo;s poverty comes from inaction; the disciple&rsquo;s loss comes from spiritual inattentiveness. The call to wakefulness in both Proverbs and the NT is the same: the time of preparation is finite, and arrival unpredictable.</p>",
    "11": "<p>&ldquo;...and poverty will come upon you like a robber, and want like an armed man.&rdquo; The violent arrival of poverty and want on the unprepared is the temporal image of the eschatological reckoning that arrives for those not prepared by wisdom and faithfulness. Matthew 25:1-13 (the ten virgins) presents the same logic: those without oil when the bridegroom arrives face a closed door. Christ the bridegroom arrives; preparedness is not optional but eschatologically decisive.</p>",
    "12": "<p>&ldquo;A worthless person, a wicked man, goes about with crooked speech.&rdquo; The portrait of the <em>ʾādām bəliyya'al</em> (man of worthlessness/Belial) — crooked speech, winking eyes, signaling feet, pointing fingers — is a composite portrait of manipulative, discord-sowing wickedness. Christ cast out the ruler of this world (John 12:31) and identified the devil as &ldquo;a liar and the father of lies&rdquo; (John 8:44), the ultimate <em>bəliyya'al</em>. The worthless man&rsquo;s tactics of deception and discord are satanic; Christ confronts them with truth and peace.</p>",
    "13": "<p>&ldquo;...winks with his eyes, signals with his feet, points with his finger.&rdquo; The covert body-language of the manipulative person — winking, signaling, pointing — is the behavioral signature of someone operating by deception rather than direct speech. Christ&rsquo;s communication is characterized by directness and clarity: &ldquo;let what you say be simply &lsquo;Yes&rsquo; or &lsquo;No&rsquo;&rdquo; (Matt 5:37); &ldquo;I have spoken openly to the world... I have said nothing in secret&rdquo; (John 18:20). The antithesis of the winking dissembler is the one who says publicly what he means.</p>",
    "14": "<p>&ldquo;With perverted heart devises evil, continually sowing discord.&rdquo; The discord-sowing heart is the deepest level of the worthless man&rsquo;s malice — the heart-level origin of all the divisive behavior. Christ said &ldquo;I have not come to bring peace, but a sword&rdquo; (Matt 10:34), but the division he brings is the necessary consequence of truth-confronting falsehood, not the purposeful discord-sowing of the worthless man. Christ also prays for the unity of his people (John 17:21-23) — the deepest anti-discord prayer in Scripture.</p>",
    "15": "<p>&ldquo;Therefore calamity will come upon him suddenly; in a moment he will be broken beyond healing.&rdquo; The sudden irreversible judgment on the discord-sower is a warning about the finality of divine judgment. Revelation 18:8 applies the same sudden-calamity language to Babylon: &ldquo;in a single day her plagues will come, death and mourning and famine.&rdquo; Christ&rsquo;s own judgment on Jerusalem was announced with similar finality (Luke 19:43-44: &ldquo;they will not leave one stone upon another in you&rdquo;), and the final judgment is &ldquo;sudden destruction&rdquo; that &ldquo;comes upon them&rdquo; (1 Thess 5:3).</p>",
    "16": "<p>&ldquo;There are six things that YHWH hates, seven that are an abomination to him.&rdquo; The <em>n/n+1</em> numerical formula introduces the seven-abomination list that functions as a counter-portrait of covenant faithfulness. Christ is the positive counter-portrait to every item: he embodies what YHWH loves, the exact opposite of each abomination. The Beatitudes (Matt 5:3-12) function similarly as the positive counter-list: blessed are the poor in spirit (not haughty), the pure in heart (not devising wickedness), the peacemakers (not sowing discord). Christ is the living Beatitude opposite each abomination.</p>",
    "17": "<p>&ldquo;Haughty eyes, a lying tongue, and hands that shed innocent blood.&rdquo; The first three abominations — haughty eyes, lying tongue, hands that shed innocent blood — are precisely inverted in Christ. He had no haughty eyes: &ldquo;learn from me, for I am gentle and lowly in heart&rdquo; (Matt 11:29). No lying tongue: &ldquo;no deceit was found in his mouth&rdquo; (1 Pet 2:22). And he did not shed innocent blood — rather, innocent blood was shed from him: Pilate&rsquo;s declaration &ldquo;I am innocent of this man&rsquo;s blood&rdquo; (Matt 27:24) is the irony of salvation history.</p>",
    "18": "<p>&ldquo;A heart that devises wicked plans, feet that make haste to run to evil.&rdquo; The wicked-planning heart and evil-running feet stand opposite to Christ&rsquo;s heart and mission. Christ&rsquo;s heart devised the plan of redemption: &ldquo;he set his face to go to Jerusalem&rdquo; (Luke 9:51) — his feet made haste not toward evil but toward the cross. Hebrews 12:2: &ldquo;for the joy that was set before him he endured the cross.&rdquo; The heart that devises salvation and the feet that run to complete it are the christological inversion of the fourth and fifth abominations.</p>",
    "19": "<p>&ldquo;A false witness who breathes out lies, and one who sows discord among brothers.&rdquo; The false witness and discord-sower complete the seven. Christ faced false witnesses at his trial (Matt 26:60-61) but was himself the true witness: &ldquo;for this purpose I was born and for this purpose I have come into the world — to bear witness to the truth&rdquo; (John 18:37). And he prays against discord: &ldquo;that they may be one, even as we are one&rdquo; (John 17:22). The last two abominations are undone by Christ&rsquo;s truthful witness and his prayer for the unity of his own.</p>",
    "20": "<p>&ldquo;My son, keep your father&rsquo;s commandment, and forsake not your mother&rsquo;s teaching.&rdquo; The parental command is to be kept and not forsaken — the same command Jesus fulfills regarding his Father&rsquo;s commands: &ldquo;I have kept my Father&rsquo;s commandments and abide in his love&rdquo; (John 15:10). The son who perfectly keeps the father&rsquo;s commandments is the son who never forsakes the mother&rsquo;s teaching — Christ&rsquo;s filial obedience was complete in both aspects, and through the Spirit he makes his people capable of the same covenant fidelity.</p>",
    "21": "<p>&ldquo;Bind them on your heart always; tie them around your neck.&rdquo; The heart-binding and neck-tying of the commandments echo Deuteronomy 6:8 and its Shema imagery — the law worn on the body as a sign of total life-orientation. Jeremiah 31:33 is the new covenant fulfillment: &ldquo;I will put my law within them, and I will write it on their hearts.&rdquo; Christ is the mediator of this writing: through the Spirit (2 Cor 3:3 — &ldquo;written not with ink but with the Spirit of the living God... on tablets of human hearts&rdquo;), the external binding becomes internal reality.</p>",
    "22": "<p>&ldquo;When you walk, they will lead you; when you lie down, they will watch over you; and when you awake, they will talk with you.&rdquo; The constant companionship of the commandments — guidance walking, protection sleeping, conversation waking — describes the relationship that Christ himself provides to his disciples: &ldquo;I will not leave you as orphans; I will come to you&rdquo; (John 14:18); &ldquo;behold, I am with you always, to the end of the age&rdquo; (Matt 28:20). The commandment&rsquo;s three-mode presence (walking, sleeping, waking) corresponds to Christ&rsquo;s all-mode presence.</p>",
    "23": "<p>&ldquo;For the commandment is a lamp and the teaching a light, and the reproofs of discipline are the way of life.&rdquo; The commandment-as-lamp and teaching-as-light anticipate Christ&rsquo;s self-identification as the light (John 8:12; 9:5: &ldquo;I am the light of the world&rdquo;) and the word about Christ as a &ldquo;lamp shining in a dark place&rdquo; (2 Pet 1:19). Psalm 119:105 — &ldquo;your word is a lamp to my feet and a light to my path&rdquo; — is fulfilled in the incarnate Word who is himself the light. The &ldquo;way of life&rdquo; that discipline opens is ultimately the way of life that Christ himself is (John 14:6).</p>",
    "24": "<p>&ldquo;To preserve you from the evil woman, from the smooth tongue of the adulteress.&rdquo; The protective function of the commandment-lamp is specifically to guard from the adulteress&rsquo;s smooth tongue — the seductive false teaching that draws away from covenant fidelity. Paul warns of the same danger to the church: &ldquo;I am afraid that as the serpent deceived Eve by his cunning, your thoughts will be led astray from a sincere and pure devotion to Christ&rdquo; (2 Cor 11:3). The church&rsquo;s guard against spiritual adultery is the lamp of Christ&rsquo;s word illuminating her path.</p>",
    "25": "<p>&ldquo;Do not desire her beauty in your heart, and do not let her capture you with her eyelashes.&rdquo; The heart-level warning against desiring the adulteress&rsquo;s beauty connects to Christ&rsquo;s own teaching on adultery in the heart (Matt 5:28). The desire that begins in the heart is where both the offense and the remedy operate: &ldquo;let the word of Christ dwell in you richly&rdquo; (Col 3:16) is the positive displacement — a heart so filled with Christ&rsquo;s word has no room for the adulteress&rsquo;s beauty to take captive.</p>",
    "26": "<p>&ldquo;For the price of a prostitute is only a loaf of bread, but a married woman hunts down a precious life.&rdquo; The destructive power of adultery beyond the prostitute&rsquo;s toll — hunting the precious life — frames the cost in terms of the soul&rsquo;s worth. Christ&rsquo;s declaration: &ldquo;what does it profit a man to gain the whole world and forfeit his soul?&rdquo; (Matt 16:26). The adulteress reduces the precious soul to less than a loaf of bread; Christ declares the soul worth more than the entire world. These two evaluations stand in direct contrast.</p>",
    "27": "<p>&ldquo;Can a man carry fire next to his chest and his clothes not be burned?&rdquo; The fire-next-to-the-chest impossibility makes a point about the unavoidable consequences of certain actions. James uses fire language similarly for the tongue (Jas 3:5-6), but Proverbs&rsquo; fire is sexual temptation. Song of Solomon 8:6 identifies love as &ldquo;a flame, a most vehement flame&rdquo; — the same fire, but in the covenant context of marriage. Christ transforms the destructive fire of illicit passion into the purifying fire of covenantal love: &ldquo;I came to cast fire on the earth, and would that it were already kindled!&rdquo; (Luke 12:49).</p>",
    "28": "<p>&ldquo;Or can one walk on hot coals and his feet not be scorched?&rdquo; The scorching-feet corollary of the fire-in-the-chest proverb completes the picture of unavoidable consequence. The same coals imagery appears in the gospel: the fire of charcoal by which Peter denied Jesus (John 18:18) and the charcoal fire by which the risen Christ restored him (John 21:9) — the coals of denial displaced by the coals of restoration. Christ does not avoid the fire of consequence but enters it to bring restoration out of the place of burning.</p>",
    "29": "<p>&ldquo;So is he who goes in to his neighbor&rsquo;s wife; none who touches her will go unpunished.&rdquo; The unpunished-none of adultery corresponds to the holy law that will not allow transgression to escape without consequence. Hebrews 2:2-3: &ldquo;if the message declared by angels proved to be reliable, and every transgression or disobedience received a just retribution, how shall we escape if we neglect such a great salvation?&rdquo; The &ldquo;none will go unpunished&rdquo; of Proverbs is answered by Christ who bore the punishment for his people — so that through him, the punished ones are acquitted.</p>",
    "30": "<p>&ldquo;People do not despise a thief if he steals to satisfy his appetite when he is hungry.&rdquo; The relativizing of the thief&rsquo;s guilt when driven by necessity opens a reflection on mercy and law. Christ engaged precisely this tension: the disciples plucked grain on the Sabbath (Matt 12:1-4), and Jesus cited David eating the showbread to justify necessity over strict legal observance. &ldquo;The Sabbath was made for man, not man for the Sabbath&rdquo; (Mark 2:27) — Christ reads the law through the lens of human need, as Proverbs 6:30 implicitly does for the hungry thief.</p>",
    "31": "<p>&ldquo;Yet if he is caught, he will pay sevenfold; he will give all the goods of his house.&rdquo; The sevenfold restitution — paying all his goods — points to the extreme cost of transgression. Christ paid the infinite cost of human transgression not by restitution of goods but by giving himself: &ldquo;you were ransomed from the futile ways inherited from your forefathers, not with perishable things such as silver or gold, but with the precious blood of Christ&rdquo; (1 Pet 1:18-19). The sevenfold restitution of goods is the temporal image of the infinitely costly ransom that Christ paid.</p>",
    "32": "<p>&ldquo;He who commits adultery lacks sense; he who does it destroys himself.&rdquo; The adultery-as-self-destruction diagnosis identifies the moral irrationality at the heart of covenant-breaking. Paul&rsquo;s teaching on sexual sin carries the same logic: &ldquo;the sexually immoral person sins against his own body&rdquo; (1 Cor 6:18) — self-destruction at the deepest level. Christ&rsquo;s redemption of those who have destroyed themselves through adultery and sexual sin is explicit in the Gospel narratives: the woman caught in adultery (John 8:11: &ldquo;neither do I condemn you; go, and from now on sin no more&rdquo;).</p>",
    "33": "<p>&ldquo;He will get wounds and dishonor, and his disgrace will not be wiped away.&rdquo; The permanent dishonor of the adulterer — wounds that cannot be healed, disgrace that cannot be erased — stands against the promise of Christ who wipes away all disgrace. Isaiah 54:4: &ldquo;you will forget the shame of your youth, and the reproach of your widowhood you will remember no more.&rdquo; Revelation 21:4: &ldquo;he will wipe away every tear from their eyes.&rdquo; The disgrace that Proverbs declares permanent is dissolved in the grace of the new covenant — the wounds healed, the dishonor reversed.</p>",
    "34": "<p>&ldquo;For jealousy makes a man furious, and he will not spare when he takes revenge.&rdquo; The husband&rsquo;s jealous fury at the adulterer is a creaturely echo of the divine jealousy that YHWH declares for his covenant people: &ldquo;I YHWH your God am a jealous God&rdquo; (Exod 20:5). 2 Cor 11:2: &ldquo;I feel a divine jealousy for you, since I betrothed you to one husband.&rdquo; Paul&rsquo;s divine jealousy for the church is the apostolic expression of Christ&rsquo;s covenant-husband jealousy — the jealousy not of insecurity but of rightful covenant love protecting its own.</p>",
    "35": "<p>&ldquo;He will accept no compensation; he will refuse though you multiply gifts.&rdquo; The husband&rsquo;s refusal to accept any payment for the adultery — no bribe can undo it — underscores the absolute nature of the covenant violation. Yet Christ accepts the ultimate compensation: not from the adulterer but from himself, paying what the guilty party cannot pay. His &ldquo;it is finished&rdquo; (John 19:30) is the declaration that the debt no human gift could cover has been fully paid by the one who was both sinned-against and redeemer — the covenant husband who bears the betrayal and the cost simultaneously.</p>"
  }
}

def main():
    existing = load_comm('mkt-christ', 'proverbs')
    merge_comm(existing, CHRIST)
    save_comm('mkt-christ', 'proverbs', existing)
    total = sum(len(vv) for vv in CHRIST.values())
    print(f'proverbs mkt-christ: wrote {total} verses for ch 4–6')

if __name__ == '__main__':
    main()
